  const [showNotifications, setShowNotifications] = useState(false);
  const [showShortcutsModal, setShowShortcutsModal] = useState(false);
  const notifRef = useRef<HTMLDivElement>(null);
  const notifTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const location = useLocation();
  const navigate = useNavigate();

  async function handleResendVerification() {
    try {
      const token = getToken();
      await fetch('/api/auth/resend-verification', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
      });
      setVerificationSent(true);
    } catch {
      // silently fail
    }
  }

  // PWA Install prompt
  useEffect(() => {
    const handler = (e: Event) => {
      e.preventDefault();
      setInstallPrompt(e as BeforeInstallPromptEvent);
      if (!localStorage.getItem('pwa-install-dismissed')) {
        setShowInstallBanner(true);
      }
    };
    window.addEventListener('beforeinstallprompt', handler);
    window.addEventListener('appinstalled', () => {
      setIsInstalled(true);
      setInstallPrompt(null);
      setShowInstallBanner(false);
    });
    if (window.matchMedia('(display-mode: standalone)').matches) {
      setIsInstalled(true);
    }
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  async function handleInstall() {
    if (!installPrompt) return;
    installPrompt.prompt();
    const result = await installPrompt.userChoice;
    if (result.outcome === 'accepted') {
      setIsInstalled(true);
      setInstallPrompt(null);
      setShowInstallBanner(false);
    }
  }

  function dismissInstallBanner() {
    setShowInstallBanner(false);
    localStorage.setItem('pwa-install-dismissed', '1');
  }

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('darkMode', String(darkMode));
  }, [darkMode]);

  // Close mobile menu on navigation
  useEffect(() => {
    setMobileMenuOpen(false);
  }, [location.pathname]);

  // Fetch low stock alerts
  useEffect(() => {
    async function checkLowStock() {
      try {
        const token = getToken();
        if (!token) return;
        const res = await fetch('/api/ingredients', {
          headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) return;
        const data = await res.json();
        const ingredients = Array.isArray(data) ? data : data.ingredients || [];
        const lowStock = ingredients
          .filter((ing: any) => {
            const qty = ing.currentStock ?? ing.quantity ?? 0;
            const threshold = ing.minimumStock ?? ing.minStock ?? ing.threshold ?? 5;
            return qty > 0 && qty < threshold;
          })
          .slice(0, 5)
          .map((ing: any) => ({
            name: ing.name,
            quantity: ing.currentStock ?? ing.quantity ?? 0,
            unit: ing.unit || 'kg',
          }));
        setStockAlerts(lowStock);
      } catch {
        // silently fail
      }
    }
    checkLowStock();
  }, [selectedRestaurant?.id]);

  // Close notification dropdown on click outside
  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (notifRef.current && !notifRef.current.contains(e.target as Node)) {
